1	import {
2	  type CSSProperties,
3	  type JSX,
4	  type KeyboardEvent,
5	  type ReactNode,
6	  useCallback,
7	  useEffect,
8	  useMemo,
9	  useRef,
10	  useState,
11	} from 'react';
12	import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';
13	
14	/**
15	 * LeftRail / Project Browser — spec §12.
16	 *
17	 * - Sticky header with a search field that filters every row by label / id.
18	 * - Vertically stacked sections (PROJECT / VIEWS / SHEETS / SCHEDULES /
19	 *   FAMILIES / EVIDENCE) with uppercase eyebrow labels.
20	 * - `role="tree"` semantics; each row is a `treeitem` with `aria-expanded`
21	 *   when it has children. Disclosure triangle is a lucide chevron.
22	 * - Keyboard: `ArrowDown`/`ArrowUp` move focus row-to-row; `ArrowRight`
23	 *   expands a closed parent or moves into its first child; `ArrowLeft`
24	 *   collapses an open parent or moves to its parent. `Enter` activates
25	 *   the focused row. `F2` invokes `onRename(rowId)`.
26	 *
27	 * Caller owns activeRowId, expansion state by default (uncontrolled), and
28	 * drag-drop reorder. The collapsed (icon-strip) variant is exposed as
29	 * `<LeftRailCollapsed/>` so AppShell can swap on `[`.
30	 */
31	
32	export type LeftRailSection = {
33	  id: string;
34	  label: string;
35	  icon?: LucideLikeIcon;
36	  rows: LeftRailRow[];
37	};
38	
39	export type LeftRailRow = {
40	  id: string;
41	  label: string;
42	  /** Lucide icon component to render at 12 px. Optional. */
43	  icon?: LucideLikeIcon;
44	  /** Subrows if any — drives the disclosure triangle and `aria-expanded`. */
45	  children?: LeftRailRow[];
46	  /** Optional secondary line shown after the label (muted). */
47	  hint?: string;
48	};
49	
50	export interface LeftRailProps {
51	  sections: LeftRailSection[];
52	  activeRowId?: string;
53	  onRowActivate?: (id: string) => void;
54	  onRowRename?: (id: string) => void;
55	  /** Initial expanded set; uncontrolled. */
56	  defaultExpanded?: ReadonlySet<string>;
57	  /** Optional hook for context-menu invocation (right-click). */
58	  onRowContextMenu?: (id: string, event: { x: number; y: number }) => void;
59	}
60	
61	/** Flatten sections + rows into a focusable order list. */
62	function flatten(
63	  sections: LeftRailSection[],
64	  expanded: ReadonlySet<string>,
65	): { id: string; depth: number; row: LeftRailRow; sectionId: string }[] {
66	  const out: { id: string; depth: number; row: LeftRailRow; sectionId: string }[] = [];
67	  function visit(rows: LeftRailRow[], depth: number, sectionId: string): void {
68	    for (const r of rows) {
69	      out.push({ id: r.id, depth, row: r, sectionId });
70	      if (r.children && r.children.length && expanded.has(r.id)) {
71	        visit(r.children, depth + 1, sectionId);
72	      }
73	    }
74	  }
75	  for (const s of sections) visit(s.rows, 0, s.id);
76	  return out;
77	}
78	
79	function matchesQuery(row: LeftRailRow, q: string): boolean {
80	  if (!q) return true;
81	  const needle = q.toLowerCase();
82	  if (row.label.toLowerCase().includes(needle)) return true;
83	  if (row.id.toLowerCase().includes(needle)) return true;
84	  if (row.hint?.toLowerCase().includes(needle)) return true;
85	  if (row.children) return row.children.some((c) => matchesQuery(c, q));
86	  return false;
87	}
88	
89	function filterRows(rows: LeftRailRow[], q: string): LeftRailRow[] {
90	  if (!q) return rows;
91	  const out: LeftRailRow[] = [];
92	  for (const r of rows) {
93	    if (matchesQuery(r, q)) {
94	      const filteredChildren = r.children ? filterRows(r.children, q) : undefined;
95	      out.push({ ...r, children: filteredChildren });
96	    }
97	  }
98	  return out;
99	}
100	
101	export function LeftRail({
102	  sections,
103	  activeRowId,
104	  onRowActivate,
105	  onRowRename,
106	  defaultExpanded,
107	  onRowContextMenu,
108	}: LeftRailProps): JSX.Element {
109	  const [expanded, setExpanded] = useState<Set<string>>(() => new Set(defaultExpanded ?? []));
110	  const [query, setQuery] = useState('');
111	  const [focusedId, setFocusedId] = useState<string | undefined>(activeRowId);
112	
113	  const filteredSections = useMemo(
114	    () =>
115	      query
116	        ? sections
117	            .map((s) => ({ ...s, rows: filterRows(s.rows, query) }))
118	            .filter((s) => s.rows.length > 0)
119	        : sections,
120	    [sections, query],
121	  );
122	
123	  // Auto-expand all rows during search so matches are visible.
124	  const liveExpanded = useMemo(() => {
125	    if (!query) return expanded;
126	    const all = new Set<string>(expanded);
127	    function collect(rows: LeftRailRow[]): void {
128	      for (const r of rows) {
129	        if (r.children?.length) {
130	          all.add(r.id);
131	          collect(r.children);
132	        }
133	      }
134	    }
135	    for (const s of filteredSections) collect(s.rows);
136	    return all;
137	  }, [filteredSections, expanded, query]);
138	
139	  const flat = useMemo(
140	    () => flatten(filteredSections, liveExpanded),
141	    [filteredSections, liveExpanded],
142	  );
143	
144	  const moveFocus = useCallback(
145	    (delta: 1 | -1) => {
146	      if (!flat.length) return;
147	      const idx = focusedId ? flat.findIndex((r) => r.id === focusedId) : -1;
148	      const next = flat[(idx + delta + flat.length) % flat.length];
149	      setFocusedId(next.id);
150	    },
151	    [flat, focusedId],
152	  );
153	
154	  const handleKey = useCallback(
155	    (event: KeyboardEvent<HTMLDivElement>) => {
156	      if (event.key === 'ArrowDown') {
157	        event.preventDefault();
158	        moveFocus(1);
159	      } else if (event.key === 'ArrowUp') {
160	        event.preventDefault();
161	        moveFocus(-1);
162	      } else if (event.key === 'ArrowRight') {
163	        if (!focusedId) return;
164	        event.preventDefault();
165	        setExpanded((prev) => {
166	          const next = new Set(prev);
167	          next.add(focusedId);
168	          return next;
169	        });
170	      } else if (event.key === 'ArrowLeft') {
171	        if (!focusedId) return;
172	        event.preventDefault();
173	        setExpanded((prev) => {
174	          if (!prev.has(focusedId)) return prev;
175	          const next = new Set(prev);
176	          next.delete(focusedId);
177	          return next;
178	        });
179	      } else if (event.key === 'Enter') {
180	        if (!focusedId) return;
181	        event.preventDefault();
182	        onRowActivate?.(focusedId);
183	      } else if (event.key === 'F2') {
184	        if (!focusedId) return;
185	        event.preventDefault();
186	        onRowRename?.(focusedId);
187	      }
188	    },
189	    [focusedId, moveFocus, onRowActivate, onRowRename],
190	  );
191	
192	  return (
193	    <div className="flex h-full flex-col overflow-hidden bg-surface">
194	      <div className="sticky top-0 z-10 border-b border-border bg-surface px-3 py-2">
195	        <SearchField value={query} onChange={setQuery} />
196	      </div>
197	      <div
198	        role="tree"
199	        aria-label="Project browser"
200	        tabIndex={0}
201	        onKeyDown={handleKey}
202	        className="flex-1 overflow-y-auto py-2"
203	      >
204	        {filteredSections.map((s) => (
205	          <SectionBlock key={s.id} section={s}>
206	            {s.rows.map((r) => (
207	              <Row
208	                key={r.id}
209	                row={r}
210	                depth={0}
211	                expanded={liveExpanded}
212	                onToggle={(id) =>
213	                  setExpanded((prev) => {
214	                    const next = new Set(prev);
215	                    if (next.has(id)) next.delete(id);
216	                    else next.add(id);
217	                    return next;
218	                  })
219	                }
220	                onActivate={onRowActivate}
221	                onContextMenu={onRowContextMenu}
222	                activeRowId={activeRowId}
223	                focusedRowId={focusedId}
224	                setFocused={setFocusedId}
225	              />
226	            ))}
227	          </SectionBlock>
228	        ))}
229	        {filteredSections.length === 0 ? (
230	          <div className="px-5 py-3 text-xs text-muted">No matches.</div>
231	        ) : null}
232	      </div>
233	    </div>
234	  );
235	}
236	
237	/** Slim (56 px) icon strip used by AppShell when the rail is collapsed. */
238	export function LeftRailCollapsed({ sections }: { sections: LeftRailSection[] }): JSX.Element {
239	  return (
240	    <nav
241	      aria-label="Project browser sections"
242	      className="flex h-full flex-col items-center gap-2 border-r border-border bg-surface py-3"
243	    >
244	      {sections.map((s) => {
245	        const Icon = s.icon ?? Icons.disclosureClosed;
246	        return (
247	          <button
248	            key={s.id}
249	            type="button"
250	            aria-label={s.label}
251	            title={s.label}
252	            className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-surface-strong"
253	          >
254	            <Icon size={ICON_SIZE.toolPalette} aria-hidden="true" />
255	          </button>
256	        );
257	      })}
258	    </nav>
259	  );
260	}
261	
262	function SearchField({
263	  value,
264	  onChange,
265	}: {
266	  value: string;
267	  onChange: (v: string) => void;
268	}): JSX.Element {
269	  return (
270	    <label className="flex items-center gap-2 rounded-md border border-border bg-background px-2 py-1.5 text-sm">
271	      <Icons.search size={ICON_SIZE.chrome} className="text-muted" aria-hidden="true" />
272	      <input
273	        type="search"
274	        placeholder="Search project"
275	        aria-label={IconLabels.search}
276	        value={value}
277	        onChange={(e) => onChange(e.target.value)}
278	        className="flex-1 bg-transparent text-sm text-foreground outline-none placeholder:text-muted"
279	      />
280	    </label>
281	  );
282	}
283	
284	function SectionBlock({
285	  section,
286	  children,
287	}: {
288	  section: LeftRailSection;
289	  children: ReactNode;
290	}): JSX.Element {
291	  return (
292	    <div className="mb-2">
293	      <div
294	        className="flex items-center gap-1.5 px-5 py-1 text-xs uppercase text-muted"
295	        style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
296	      >
297	        {section.icon ? <section.icon size={12} aria-hidden="true" /> : null}
298	        <span>{section.label}</span>
299	      </div>
300	      {children}
301	    </div>
302	  );
303	}
304	
305	interface RowProps {
306	  row: LeftRailRow;
307	  depth: number;
308	  expanded: ReadonlySet<string>;
309	  onToggle: (id: string) => void;
310	  onActivate?: (id: string) => void;
311	  onContextMenu?: (id: string, event: { x: number; y: number }) => void;
312	  activeRowId?: string;
313	  focusedRowId?: string;
314	  setFocused: (id: string) => void;
315	}
316	
317	function Row({
318	  row,
319	  depth,
320	  expanded,
321	  onToggle,
322	  onActivate,
323	  onContextMenu,
324	  activeRowId,
325	  focusedRowId,
326	  setFocused,
327	}: RowProps): JSX.Element {
328	  const hasChildren = !!row.children?.length;
329	  const isOpen = expanded.has(row.id);
330	  const isActive = row.id === activeRowId;
331	  const isFocused = row.id === focusedRowId;
332	  const ref = useRef<HTMLButtonElement | null>(null);
333	
334	  useEffect(() => {
335	    if (isFocused) ref.current?.focus({ preventScroll: true });
336	  }, [isFocused]);
337	
338	  const indentStyle: CSSProperties = {
339	    paddingLeft: `calc(var(--space-5) + ${depth} * var(--space-5))`,
340	  };
341	
342	  return (
343	    <div role="none">
344	      <button
345	        ref={ref}
346	        type="button"
347	        role="treeitem"
348	        aria-level={depth + 1}
349	        aria-expanded={hasChildren ? isOpen : undefined}
350	        aria-selected={isActive}
351	        tabIndex={isFocused ? 0 : -1}
352	        onClick={() => {
353	          setFocused(row.id);
354	          if (hasChildren) onToggle(row.id);
355	          onActivate?.(row.id);
356	        }}
357	        onContextMenu={(event) => {
358	          if (!onContextMenu) return;
359	          event.preventDefault();
360	          onContextMenu(row.id, { x: event.clientX, y: event.clientY });
361	        }}
362	        data-testid={`left-rail-row-${row.id}`}
363	        data-active={isActive ? 'true' : 'false'}
364	        style={indentStyle}
365	        className={[
366	          'flex h-7 w-full items-center gap-1.5 pr-3 text-sm',
367	          isActive ? 'bg-accent-soft text-foreground' : 'text-foreground hover:bg-surface-strong',
368	        ].join(' ')}
369	      >
370	        <span className="inline-flex w-4 items-center justify-center">
371	          {hasChildren ? (
372	            isOpen ? (
373	              <Icons.disclosureOpen size={12} aria-hidden="true" />
374	            ) : (
375	              <Icons.disclosureClosed size={12} aria-hidden="true" />
376	            )
377	          ) : null}
378	        </span>
379	        {row.icon ? <row.icon size={12} aria-hidden="true" className="text-muted" /> : null}
380	        <span className="truncate">{row.label}</span>
381	        {row.hint ? <span className="ml-auto truncate text-xs text-muted">{row.hint}</span> : null}
382	      </button>
383	      {hasChildren && isOpen
384	        ? (row.children ?? []).map((c) => (
385	            <Row
386	              key={c.id}
387	              row={c}
388	              depth={depth + 1}
389	              expanded={expanded}
390	              onToggle={onToggle}
391	              onActivate={onActivate}
392	              onContextMenu={onContextMenu}
393	              activeRowId={activeRowId}
394	              focusedRowId={focusedRowId}
395	              setFocused={setFocused}
396	            />
397	          ))
398	        : null}
399	    </div>
400	  );
401	}
