const redrawPreviewRectMm = (x0Mm: number, y0Mm: number, x1Mm: number, y1Mm: number) => {
  const xMn = Math.min(x0Mm, x1Mm) / 1000;
  const xMx = Math.max(x0Mm, x1Mm) / 1000;
